```typescript
class TypedEmitter<Events extends Record<string, unknown[]>> {
  private handlers = new Map<string, Function[]>();

  on<E extends keyof Events>(event: E, fn: (...args: Events[E]) => void) {
    const list = this.handlers.get(event as string) ?? [];
    list.push(fn);
    this.handlers.set(event as string, list);
  }

  emit<E extends keyof Events>(event: E, ...args: Events[E]) {
    this.handlers.get(event as string)?.forEach(fn => fn(...args));
  }
}

const bus = new TypedEmitter<{
  login: [userId: string];
  purchase: [item: string, amount: number];
}>();

bus.on("purchase", (item, amount) => {
  // item: string, amount: number — fully inferred
});

bus.emit("login", 42); // compile error — expects string
```

